import functools
import time

# Basic decorator
def timer(func):
    @functools.wraps(func)  # preserves original function's __name__ and __doc__
    def wrapper(*args, **kwargs):
        start = time.perf_counter()
        result = func(*args, **kwargs)  # call original function
        elapsed = time.perf_counter() - start
        print(f'{func.__name__} took {elapsed:.4f}s')
        return result
    return wrapper

@timer
def slow_operation():
    time.sleep(0.1)
    return 'done'

slow_operation()  # Output: slow_operation took 0.1001s

# Decorator factory (takes arguments)
def retry(max_attempts=3):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            for attempt in range(max_attempts):
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    if attempt == max_attempts - 1:
                        raise
                    print(f'Retrying ({attempt+1}/{max_attempts})...')
        return wrapper
    return decorator

@retry(max_attempts=3)
def flaky_api_call():
    import random
    if random.random() < 0.7:
        raise ConnectionError('timeout')
    return 'success'

# *args: variable positional arguments -> tuple
def sum_all(*numbers):
    return sum(numbers)

sum_all(1, 2, 3)        # 6
sum_all(1, 2, 3, 4, 5)  # 15

# **kwargs: variable keyword arguments -> dict
def create_user(name, **options):
    user = {'name': name}
    user.update(options)
    return user

create_user('Alice', age=30, role='admin')
# {'name': 'Alice', 'age': 30, 'role': 'admin'}

# Combined: positional, *args, keyword-only, **kwargs
def log(level, *messages, timestamp=True, **metadata):
    prefix = f'[{level}]'
    for msg in messages:
        print(f'{prefix} {msg}', metadata)

log('INFO', 'Server started', 'Listening on :8080', port=8080)

