# Forwarding in decorators
def log_call(func):
    def wrapper(*args, **kwargs):    # accepts ANY signature
        print(f'Calling {func.__name__}')
        return func(*args, **kwargs) # forwards all args unchanged
    return wrapper

class Vector:
    def __init__(self, x, y):
        self.x, self.y = x, y

    def __repr__(self):     # technical representation (for debugging)
        return f'Vector({self.x}, {self.y})'

    def __str__(self):      # human-friendly string (for print())
        return f'<{self.x}, {self.y}>'

    def __add__(self, other): # enables v1 + v2
        return Vector(self.x + other.x, self.y + other.y)

    def __len__(self):       # enables len(v)
        return int((self.x**2 + self.y**2) ** 0.5)

    def __eq__(self, other): # enables v1 == v2
        return self.x == other.x and self.y == other.y

    def __iter__(self):      # enables for x in v and list(v)
        yield self.x
        yield self.y

    def __getitem__(self, idx): # enables v[0], v[1]
        return (self.x, self.y)[idx]

v1 = Vector(3, 4)
v2 = Vector(1, 2)
print(v1)          # <3, 4>   (calls __str__)
print(v1 + v2)     # <4, 6>   (calls __add__)
print(len(v1))     # 5        (calls __len__)
print(v1 == v2)    # False    (calls __eq__)
print(list(v1))    # [3, 4]   (calls __iter__)
print(v1[0])       # 3        (calls __getitem__)

from datetime import datetime

class Employee:
    company = 'Acme Corp'  # class attribute

    def __init__(self, name, salary):
        self.name = name
        self._salary = salary  # 'private' by convention

    # Instance method: accesses self
    def annual_package(self):
        return self._salary * 12

    # classmethod: alternative constructor pattern
    @classmethod
    def from_dict(cls, data):
        return cls(data['name'], data['salary'])

    # staticmethod: utility, no instance or class needed
    @staticmethod
    def is_valid_salary(amount):
        return isinstance(amount, (int, float)) and amount > 0

    # property: computed attribute with getter
    @property
    def salary(self):
        return self._salary

    # setter: enables e.salary = 5000 with validation
    @salary.setter
    def salary(self, value):
        if not Employee.is_valid_salary(value):
            raise ValueError(f'Invalid salary: {value}')
        self._salary = value

e = Employee('Alice', 4000)
e.salary = 5000              # calls setter
print(e.salary)              # 5000 (calls getter)
print(e.annual_package())    # 60000

e2 = Employee.from_dict({'name': 'Bob', 'salary': 3000})  # classmethod
print(Employee.is_valid_salary(-100))  # False (staticmethod)

# Duck typing: no isinstance() checks needed
def process_file(file_like):
    content = file_like.read()  # only requires .read() method
    return content.upper()

from io import StringIO
process_file(open('data.txt'))       # real file
process_file(StringIO('hello'))      # string buffer — works!
process_file(urllib.request.urlopen('...'))  # URL — works!
# All 'duck' the same way — they all have .read()

# EAFP style (Easier to Ask Forgiveness than Permission)
# Pythonic: try it, catch exceptions
def get_length(obj):
    try:
        return len(obj)
    except TypeError:
        return None  # doesn't support len()

# LBYL (Look Before You Leap) — more verbose, less Pythonic
def get_length_lbyl(obj):
    if hasattr(obj, '__len__'):
        return len(obj)
    return None

# Formal Protocol (Python 3.8+)
from typing import Protocol

class Drawable(Protocol):
    def draw(self) -> None: ...
    def resize(self, factor: float) -> None: ...

# Any class with draw() and resize() satisfies Drawable
# No inheritance needed
class Circle:
    def draw(self): print('O')
    def resize(self, f): self.radius *= f

def render(shape: Drawable):
    shape.draw()  # type-safe — Protocol guarantees .draw() exists
